    let gain2 = required_f32(params, "gain2").map_err(anyhow::Error::msg)?;
    let gain3 = required_f32(params, "gain3").map_err(anyhow::Error::msg)?;
    let gain4 = required_f32(params, "gain4").map_err(anyhow::Error::msg)?;
    let gain5 = required_f32(params, "gain5").map_err(anyhow::Error::msg)?;
